INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_103', 'Tiny Toadstool', 'A storybook mushroom — a domed cap on a little stalk. A two-piece project that introduces simple assembly.', 'Beginner', 'Amigurumi', '["woodland","cute","decor"]', NULL, '3.5 mm', 'DK', '2–3 hrs', 'Approximately 7 cm (3 in) at the largest dimension', '["DK yarn in rust, cream","3.5 mm hook","Tapestry needle","Scissors","Polyfill stuffing","Stitch marker"]', '[]', '["Cap — in rust yarn: work the following in continuous rounds.","Cap — Round 1: Magic ring. 6 single crochet into ring. Pull ring closed. (6 stitches)","Cap — Round 2: 2 single crochet in each stitch around. (12 stitches)","Cap — Round 3: [Single crochet in next stitch, 2 single crochet in next stitch] repeat 6 times. (18 stitches)","Cap — Round 4: [Single crochet in next 2 stitches, 2 single crochet in next stitch] repeat 6 times. (24 stitches)","Cap — Round 5: [Single crochet in next 3 stitches, 2 single crochet in next stitch] repeat 6 times. (30 stitches)","Cap — Round 6: [Single crochet in next 4 stitches, 2 single crochet in next stitch] repeat 6 times. (36 stitches)","Cap — Round 7: [Single crochet in next 5 stitches, 2 single crochet in next stitch] repeat 6 times. (42 stitches)","Cap — Round 8: [Single crochet in next 6 stitches, 2 single crochet in next stitch] repeat 6 times. (48 stitches)","Cap — Round 9: [Single crochet in next 7 stitches, 2 single crochet in next stitch] repeat 6 times. (54 stitches)","Cap — Round 10: Single crochet in each stitch around. (54 stitches)","Cap — Finishing: Fasten off leaving a long tail for sewing.","Stem — in cream yarn: work the following in continuous rounds.","Stem — Round 1: Magic ring. 6 single crochet into ring. Pull ring closed. (6 stitches)","Stem — Round 2: 2 single crochet in each stitch around. (12 stitches)","Stem — Round 3: [Sin