INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_113', 'Newborn Beanie', 'A snug worked-in-the-round beanie sized for a newborn. The joined double-crochet crown grows by a predictable rhythm.', 'Beginner', 'Wearable', '["baby","hat","gift"]', NULL, '5.0 mm', 'Worsted', '2–3 hrs', 'See pattern', '["Worsted yarn in rose","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Beanie — in rose yarn: work the following in continuous rounds.","Beanie — Round 1: Magic ring. Chain 2 (does not count as a stitch), 12 single crochet into ring. Join with a slip stitch to the first single crochet. (12 stitches)","Beanie — Round 2: Chain 2 (does not count as a stitch), 2 single crochet in each stitch around. (24 stitches) Join with a slip stitch.","Beanie — Round 3: Chain 2 (does not count as a stitch), [Single crochet in next stitch, 2 single crochet in next stitch] repeat 12 times. (36 stitches) Join with a slip stitch.","Beanie — Round 4: Chain 2 (does not count as a stitch), [Single crochet in next 2 stitches, 2 single crochet in next stitch] repeat 12 times. (48 stitches) Join with a slip stitch.","Beanie — Round 5: Chain 2 (does not count as a stitch), [Single crochet in next 3 stitches, 2 single crochet in next stitch] repeat 12 times. (60 stitches) Join with a slip stitch.","Beanie — Rounds 6–31: Chain 2 (does not count as a stitch), single crochet in each stitch around. (60 stitches each round) Join with a slip stitch at the end of each round.","Beanie — Brim: Work 2 rounds of single crochet in each stitch around for a clean edge. (60 stitches each round) Fasten off and weave in ends."]', '2026-06-30T00:00:00.000Z')
  ON CONFLICT(id) DO UPDATE SET name = excluded.name, description = excluded.description, difficulty = excluded.difficulty, category = excluded.category, tags = excluded.tags, imageUrl = excluded.imageUrl, hookSize = excluded.hookSize, yarnWeight = excluded.yarnWeight, timeEstimate = excluded.timeEstimate, finishedSize = excluded.finishedSize, materials = excluded.materials, notes = excluded.notes, defaultPattern = excluded.defaultPattern;
INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_114', 'Kids'' Beanie', 'A everyday beanie sized for children, worked from the crown down. A reliable, fast gift in any colour.', 'Beginner', 'Wearable', '["kids","hat","quick"]', NULL, '5.0 mm', 'Worsted', '2–3 hrs', 'See pattern', '["Worsted yarn in teal","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Beanie — in teal yarn: work the following in continuous rounds.","Beanie — Round 1: Magic ring. Chain 2 (does not count as a stitch), 12 single crochet into ring. Join with a slip stitch to the first single crochet. (12 stitches)","Beanie — Round 2: Chain 2 (does not count as a stitch), 2 single crochet in each stitch around. (24 stitches) Join with a slip stitch.","Beanie — Round 3: Chain 2 (does not count as a stitch), [Single crochet in next stitch, 2 single crochet in next stitch] repeat 12 times. (36 stitches) Join with a slip stitch.","Beanie — Round 4: Chain 2 (does not count as a stitch), [Single crochet in next 2 stitches, 2 single crochet in next stitch] repeat 12 times. (48 stitches) Join with a slip stitch.","Beanie — Round 5: Chain 2 (does not count as a stitch), [Single crochet in next 3 stitches, 2 single crochet in next stitch] repeat 12 times. (60 stitches) Join with a slip stitch.","Beanie — Round 6: Chain 2 (does not count as a stitch), [Single crochet in next 4 stitches, 2 single crochet in next stitch] repeat 12 times. (72 stitches) Join with a slip stitch.","Beanie — Round 7: Chain 2 (does not count as a stitch), [Single crochet in next 5 stitches, 2 single crochet in next stitch] repeat 12 times. (84 stitches) Join with a slip stitch.","Beanie — Rounds 8–40: Chain 2 (does not count as a stitch), single crochet in each stitch around. (84 stitches each round) Join with a slip stitch at the end of each round.","Beanie — Brim: Work 2 rounds of single crochet in each stitch around for a clean edge. (84 stitches each round) Fasten off and weave in ends."]', '2026-06-30T00:00:00.000Z')
  ON CONFLICT(id) DO UPDATE SET name = excluded.name, description = excluded.description, difficulty = excluded.difficulty, category = excluded.category, tags = excluded.tags, imageUrl = excluded.imageUrl, hookSize = excluded.hookSize, yarnWeight = excluded.yarnWeight, timeEstimate = excluded.timeEstimate, finishedSize = excluded.finishedSize, materials = excluded.materials, notes = excluded.notes, defaultPattern = excluded.defaultPattern;
INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_115', 'Classic Adult Beanie', 'The wardrobe staple — a smooth-crowned beanie sized for adults. Master this and you can size up or down at will.', 'Intermediate', 'Wearable', '["hat","staple","unisex"]', NULL, '5.0 mm', 'Worsted', '3–4 hrs', 'See pattern', '["Worsted yarn in charcoal","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Beanie — in charcoal yarn: work the following in continuous rounds.","Beanie — Round 1: Magic ring. Chain 2 (does not count as a stitch), 12 single crochet into ring. Join with a slip stitch to the first single crochet. (12 stitches)","Beanie — Round 2: Chain 2 (does not count as a stitch), 2 single crochet in each stitch around. (24 stitches) Join with a slip stitch.","Beanie — Round 3: Chain 2 (does not count as a stitch), [Single crochet in next stitch, 2 single crochet in next stitch] repeat 12 times. (36 stitches) Join with a slip stitch.","Beanie — Round 4: Chain 2 (does not count as a stitch), [Single crochet in next 2 stitches, 2 single crochet in next stitch] repeat 12 times. (48 stitches) Join with a slip stitch.","Beanie — Round 5: Chain 2 (does not count as a stitch), [Single crochet in next 3 stitches, 2 single crochet in next stitch] repeat 12 times. (60 stitches) Join with a slip stitch.","Beanie — Round 6: Chain 2 (does not count as a stitch), [Single crochet in next 4 stitches, 2 single crochet in next stitch] repeat 12 times. (72 stitches) Join with a slip stitch.","Beanie — Round 7: Chain 2 (does not count as a stitch), [Single crochet in next 5 stitches, 2 single crochet in next stitch] repeat 12 times. (84 stitches) Join with a slip stitch.","Beanie — Round 8: Chain 2 (does not count as a stitch), [Single crochet in next 6 stitches, 2 single crochet in next stitch] repeat 12 times. (96 stitches) Join with a slip stitch.","Beanie — Rounds 9–46: Chain 2 (does not count as a stitch), single crochet in each stitch around. (96 stitches each round) Join with a slip stitch at the end of each round.","Beanie — Brim: Work 2 rounds of single crochet in each stitch around for a clean edge. (96 stitches each round) Fasten off and weave in ends."]', '2026-06-30T00:00:00.000Z')
  ON CONFLICT(id) DO UPDATE SET name = excluded.name, description = excluded.description, difficulty = excluded.difficulty, category = excluded.category, tags = excluded.tags, imageUrl = excluded.imageUrl, hookSize = excluded.hookSize, yarnWeight = excluded.yarnWeight, timeEstimate = excluded.timeEstimate, finishedSize = excluded.finishedSize, materials = excluded.materials, notes = excluded.notes, defaultPattern = excluded.defaultPattern;
INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_116', 'Striped Slouch Beanie', 'A relaxed adult slouch with bold two-round stripes. Colour cycling, computed and written into the pattern for you.', 'Intermediate', 'Wearable', '["hat","stripes","slouchy"]', NULL, '5.0 mm', 'Worsted', '3–4 hrs', 'See pattern', '["Worsted yarn in mint, cream","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Beanie — starting in mint yarn: work the following in continuous rounds.","Beanie — Round 1: Magic ring. Chain 2 (does not count as a stitch), 12 single crochet into ring. Join with a slip stitch to the first single crochet. (12 stitches)","Beanie — Round 2: Chain 2 (does not count as a stitch), 2 single crochet in each stitch around. (24 stitches) Join with a slip stitch.","Beanie — Change to cream yarn.","Beanie — Round 3: Chain 2 (does not count as a stitch), [Single crochet in next stitch, 2 single crochet in next stitch] repeat 12 times. (36 stitches) Join with a slip stitch.","Beanie — Round 4: Chain 2 (does not count as a stitch), [Single crochet in next 2 stitches, 2 single crochet in next stitch] repeat 12 times. (48 stitches) Join with a slip stitch.","Beanie — Change to mint yarn.","Beanie — Round 5: Chain 2 (does not count as a stitch), [Single crochet in next 3 stitches, 2 single crochet in next stitch] repeat 12 times. (60 stitches) Join with a slip stitch.","Beanie — Round 6: Chain 2 (does not count as a stitch), [Single crochet in next 4 stitches, 2 single crochet in next stitch] repeat 12 times. (72 stitches) Join with a slip stitch.","Beanie — Change to cream yarn.","Beanie — Round 7: Chain 2 (does not count as a stitch), [Single crochet in next 5 stitches, 2 single crochet in next stitch] repeat 12 times. (84 stitches) Join with a slip stitch.","Beanie — Round 8: Chain 2 (does not count as a stitch), [Single croc