INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_117', 'Cosy Infinity Cowl', 'A wide loop worked in the round — endless rounds of plain stitches that make a meditative, beginner-friendly wrap.', 'Beginner', 'Wearable', '["cowl","scarf","mindful"]', NULL, '6.5 mm', 'Bulky', '3–5 hrs', 'Approximately 24 cm (9 in) at the largest dimension', '["Bulky yarn in periwinkle","6.5 mm hook","Tapestry needle","Scissors"]', '[]', '["Cowl — in periwinkle yarn: work the following in continuous rounds.","Cowl — Round 1: Magic ring. 6 single crochet into ring. Pull ring closed. (6 stitches)","Cowl — Round 2: 2 single crochet in each stitch around. (12 stitches)","Cowl — Round 3: [Single crochet in next stitch, 2 single crochet in next stitch] repeat 6 times. (18 stitches)","Cowl — Round 4: [Single crochet in next 2 stitches, 2 single crochet in next stitch] repeat 6 times. (24 stitches)","Cowl — Round 5: [Single crochet in next 3 stitches, 2 single crochet in next stitch] repeat 6 times. (30 stitches)","Cowl — Round 6: [Single crochet in next 4 stitches, 2 single crochet in next stitch] repeat 6 times. (36 stitches)","Cowl — Round 7: [Single crochet in next 5 stitches, 2 single crochet in next stitch] repeat 6 times. (42 stitches)","Cowl — Round 8: [Single crochet in next 6 stitches, 2 single crochet in next stitch] repeat 6 times. (48 stitches)","Cowl — Round 9: [Single crochet in next 7 stitches, 2 single crochet in next stitch] repeat 6 times. (54 stitches)","Cowl — Round 10: [Single crochet in next 8 stitches, 2 single crochet in next stitch] repeat 6 times. (60 stitches)","Cowl — Round 11: [Single crochet in next 9 stitches, 2 single crochet in next stitch] repeat 6 times. (66 stitches)","Cowl — Round 12: [Single crochet in next 10 stitches, 2 single crochet in next stitch] repeat 6 times. (72 stitches)","Cowl — Round 13: [Single crochet in next 11 stitches, 2 single crochet in next stitch] repeat 6 times. (78 stitches)","Cowl — Round 14: [Single crochet in next 12 stitches, 2 single crochet in next stitch] repeat 6 times. (84 stitches)","Cowl — Round 15: [Single crochet in next 13 stitches, 2 single crochet in next stitch] repeat 6 times. (90 stitches)","Cowl — Rounds 16–53: Working in back loops only for this round, then through both loops: single crochet in each stitch around. (90 stitches each round)","Cowl — Finishing: Fasten off and weave in ends."]', '2026-06-30T00:00:00.000Z')
  ON CONFLICT(id) DO UPDATE SET name = excluded.name, description = excluded.description, difficulty = excluded.difficulty, category = excluded.category, tags = excluded.tags, imageUrl = excluded.imageUrl, hookSize = excluded.hookSize, yarnWeight = excluded.yarnWeight, timeEstimate = excluded.timeEstimate, finishedSize = excluded.finishedSize, materials = excluded.materials, notes = excluded.notes, defaultPattern = excluded.defaultPattern;
INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_118', 'Ribbed Ear Warmer', 'A simple band that hugs the head and keeps ears toasty. A short, satisfying make with a clean seam.', 'Beginner', 'Wearable', '["headband","quick","winter"]', NULL, '5.0 mm', 'Worsted', '1–2 hrs', 'Approximately 48 cm (19 in) at the largest dimension', '["Worsted yarn in rose","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Band — in rose yarn: work the following back and forth in rows.","Band — Foundation: Chain 19. (19 chains)","Band — Row 1: Single crochet in the 2nd chain from the hook and in each chain across. (18 stitches) Chain 1, turn.","Band — Rows 2–106: Single crochet in each stitch across. (18 stitches) Chain 1, turn. Do not chain or turn at the end of the final row.","Band — Finishing: Fasten off and weave in ends with a tapestry needle.","Assembly: Seam the two short ends together to form a loop."]', '2026-06-30T00:00:00.000Z')
  ON CONFLICT(id) DO UPDATE SET name = excluded.name, description = excluded.description, difficulty = excluded.difficulty, category = excluded.category, tags = excluded.tags, imageUrl = excluded.imageUrl, hookSize = excluded.hookSize, yarnWeight = excluded.yarnWeight, timeEstimate = excluded.timeEstimate, finishedSize = excluded.finishedSize, materials = excluded.materials, notes = excluded.notes, defaultPattern = excluded.defaultPattern;
INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_119', 'Wrist Warmers', 'A pair of plain tubes that slip over the wrists — warmth without covering the fingers. A quick, useful gift.', 'Beginner', 'Wearable', '["mitts","quick","pair"]', NULL, '5.0 mm', 'Worsted', '2–3 hrs', 'Approximately 14 cm (6 in) at the largest dimension', '["Worsted yarn in violet","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Warmer (make 2) — in violet yarn: work the following in continuous rounds.","Warmer (make 2) — Round 1: Magic ring. 6 single crochet into ring. Pull ring closed. (6 stitches)","Warmer (make 2) — Round 2: 2 single crochet in each stitch around. (12 stitches)","Warmer (make 2) — Round 3: [Single crochet in next stitch, 2 single crochet in next stitch] repeat 6 times. (18 stitches)","Warmer (make 2) — Round 4: [Single crochet in next 2 stitches, 2 single crochet in next stitch] repeat 6 times. (24 stitches)","Warmer (make 2) — Round 5: [Single crochet in next 3 stitches, 2 single crochet in next stitch] repeat 6 times. (30 stitches)","Warmer (make 2) — Round 6: [Single crochet in next 4 stitches, 2 single crochet in next stitch] repeat 6 times. (36 stitches)","Warmer (make 2) — Round 7: [Single crochet in next 5 stitches, 2 single crochet in next stitch] repeat 6 times. (42 stitches)","Warmer (make 2) — Round 8: [Single crochet in next 6 stitches, 2 single crochet in next stitch] repeat 6 times. (48 stitches)","Warmer (make 2) — Rounds 9–39: Working in back loops only for this round, then through both loops: single crochet in each stitch around. (48 stitches each round)","Warmer (make 2) — Finishing: Fasten off and weave in ends."]', '2026-06-30T00:00:00.000Z')
  ON CONFLICT(id) DO UPDATE SET name = excluded.name, description = excluded.description, difficulty = excluded.difficulty, category = excluded.category, tags = excluded.tags, imageUrl = excluded.imageUrl, hookSize = excluded.hookSize, yarnWeight = excluded.yarnWeight, timeEstimate = excluded.timeEstimate, finishedSize = excluded.finishedSize, materials = excluded.materials, notes = excluded.notes, defaultPattern = excluded.defaultPattern;
INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_120', 'Classic Granny Square', 'The building block of countless projects — clusters and corner spaces growing round by round. Make one, or a hundred.', 'Beginner', 'Accessory', '["granny","classic","modular"]', NULL, '5.0 mm', 'Worsted', '1 hr', 'Approximately 15 cm (6 in) at the largest dimension', '["Worsted yarn in marigold","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Square — in marigold yarn: work the following in continuous rounds.","Square — Round 1: Magic ring. Chain 3 (counts as first double crochet), 2 double crochet into ring, chain 2, [3 double crochet into ring, chain 2] repeat 3 times. Join with a slip stitch to the top of the chain 3. (12 stitches)","Square — Round 2: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (24 stitches)","Square — Round 3: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (36 stitches)","Square — Round 4: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (48 stitches)","Square — Round 5: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (60 stitches)","Square — Round 6: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (72 stitches)","Square — Round 7: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (84 stitches)","Square — Round 8: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (96 stitches)","Square — Round 9: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (108 stitches)","Square — Finishing: Fasten off and weave in ends."]', '2026-06-30T00:00:00.000Z')
  ON CONFLICT(id) DO UPDATE SET name = excluded.name, description = excluded.description, difficulty = excluded.difficulty, category = excluded.category, tags = excluded.tags, imageUrl = excluded.imageUrl, hookSize = excluded.hookSize, yarnWeight = excluded.yarnWeight, timeEstimate = excluded.timeEstimate, finishedSize = excluded.finishedSize, materials = excluded.materials, notes = excluded.notes, defaultPattern = excluded.defaultPattern;
INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_121', 'Sunburst Coaster', 'A small, sturdy granny worked tight to protect your tabletop. A one-sitting project to use up scraps.', 'Beginner', 'Accessory', '["coaster","quick","home"]', NULL, '5.0 mm', 'Worsted', '30–45 min', 'Approximately 10 cm (4 in) at the largest dimension', '["Worsted yarn in teal","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Coaster — in teal yarn: work the following in continuous rounds.","Coaster — Round 1: Magic ring. Chain 3 (counts as first double crochet), 2 double crochet into ring, chain 2, [3 double crochet into ring, chain 2] repeat 3 times. Join with a slip stitch to the top of the chain 3. (12 stitches)","Coaster — Round 2: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (24 stitches)","Coaster — Round 3: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (36 stitches)","Coaster — Round 4: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (48 stitches)","Coaster — Round 5: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (60 stitches)","Coaster — Round 6: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (72 stitches)","Coaster — Finishing: Fasten off and weave in ends."]', '2026-06-30T00:00:00.000Z')
  ON CONFLICT(id) DO UPDATE SET name = excluded.name, description = excluded.description, difficulty = excluded.difficulty, category = excluded.category, tags = excluded.tags, imageUrl = excluded.imageUrl, hookSize = excluded.hookSize, yarnWeight = excluded.yarnWeight, timeEstimate = excluded.timeEstimate, finishedSize = excluded.finishedSize, materials = excluded.materials, notes = excluded.notes, defaultPattern = excluded.defaultPattern;
INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_122', 'Tassel Bookmark', 'A long, narrow band worked in rows — slim enough to mark your page, with a tassel at the tip.', 'Beginner', 'Accessory', '["bookmark","quick","gift"]', NULL, '5.0 mm', 'Worsted', '45 min', 'Approximately 18 cm (7 in) at the largest dimension', '["Worsted yarn in rose","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Bookmark — in rose yarn: work the following back and forth in rows.","Bookmark — Foundation: Chain 8. (8 chains)","Bookmark — Row 1: Single crochet in the 2nd chain from the hook and in each chain across. (7 stitches) Chain 1, turn.","Bookmark — Rows 2–40: Single crochet in each stitch across. (7 stitches) Chain 1, turn. Do not chain or turn at the end of the final row.","Bookmark — Finishing: Fasten off and weave in ends with a tapestry needle.","Embellishment: Add a small tassel to one short end."]', '2026-06-30T00:00:00.000Z')
  ON CONFLICT(id) DO UPDATE SET name = excluded.name, description = excluded.description, difficulty = excluded.difficulty, category = excluded.category, tags = excluded.tags, imageUrl = excluded.imageUrl, hookSize = excluded.hookSize, yarnWeight = excluded.yarnWeight, timeEstimate = excluded.timeEstimate, finishedSize = excluded.finishedSize, materials = excluded.materials, notes = excluded.notes, defaultPattern = excluded.defaultPattern;
INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_123', 'Drawstring Pouch', 'A little worked-in-the-round bag for trinkets or treasures. Add a chain drawstring threaded through the top.', 'Intermediate', 'Accessory', '["pouch","bag","storage"]', NULL, '5.0 mm', 'Worsted', '2–3 hrs', 'Approximately 11 cm (4 in) at the largest dimension', '["Worsted yarn in periwinkle","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Pouch — in periwinkle yarn: work the following in continuous rounds.","Pouch — Round 1: Magic ring. 6 single crochet into ring. Pull ring closed. (6 stitches)","Pouch — Round 2: 2 single crochet in each stitch around. (12 stitches)","Pouch — Round 3: [Single crochet in next stitch, 2 single crochet in next stitch] repeat 6 times. (18 stitches)","Pouch — Round 4: [Single crochet in next 2 stitches, 2 single crochet in next stitch] repeat 6 times. (24 stitches)","Pouch — Round 5: [Single crochet in next 3 stitches, 2 single crochet in next stitch] repeat 6 times. (30 stitches)","Pouch — Round 6: [Single crochet in next 4 stitches, 2 single crochet in next stitch] repeat 6 times. (36 stitches)","Pouch — Round 7: [Single crochet in next 5 stitches, 2 single crochet in next stitch] repeat 6 times. (42 stitches)","Pouch — Round 8: [Single crochet in next 6 stitches, 2 single crochet in next stitch] repeat 6 times. (48 stitches)","Pouch — Rounds 9–32: Working in back loops only for this round, then through both loops: single crochet in each stitch around. (48 stitches each round)","Pouch — Finishing: Fasten off and weave in ends.","Embellishment: Thread a crocheted chain through the final round as a drawstring."]', '2026-06-30T00:00:00.000Z')
