INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_129', 'Patchwork Pillow Front', 'An oversized granny square that becomes the face of a cushion. Back it with fabric or a second square.', 'Intermediate', 'Home Decor', '["pillow","granny","statement"]', NULL, '5.0 mm', 'Worsted', '4–6 hrs', 'Approximately 40 cm (16 in) at the largest dimension', '["Worsted yarn in coral","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Panel — in coral yarn: work the following in continuous rounds.","Panel — Round 1: Magic ring. Chain 3 (counts as first double crochet), 2 double crochet into ring, chain 2, [3 double crochet into ring, chain 2] repeat 3 times. Join with a slip stitch to the top of the chain 3. (12 stitches)","Panel — Round 2: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (24 stitches)","Panel — Round 3: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (36 stitches)","Panel — Round 4: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (48 stitches)","Panel — Round 5: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (60 stitches)","Panel — Round 6: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (72 stitches)","Panel — Round 7: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (84 stitches)","Panel — Round 8: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (96 stitches)","Panel — Round 9: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (108 stitches)","Panel — Round 10: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (120 stitches)","Panel — Round 11: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (132 stitches)","Panel — Round 12: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (144 stitches)","Panel — Round 13: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (156 stitches)","Panel — Round 14: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (168 stitches)","Panel — Round 15: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (180 stitches)","Panel — Round 16: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (192 stitches)","Panel — Round 17: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (204 stitches)","Panel — Round 18: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (216 stitches)","Panel — Round 19: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (228 stitches)","Panel — Round 20: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (240 stitches)","Panel — Round 21: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (252 stitches)","Panel — Round 22: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (264 stitches)","Panel — Round 23: Slip stitch to the next corner space. Chain 3, work [2 double crochet, chain 2, 3 double crochet] in the corner space, then 3 double crochet in each side space and [3 double crochet, chain 2, 3 double crochet] in each remaining corner space around. Join with a slip stitch. (276 stitches)","Panel — Finishing: Fasten off and weave in ends."]', '2026-06-30T00:00:00.000Z')
