INSERT INTO templates (id, name, description, difficulty, category, tags, imageUrl, hookSize, yarnWeight, timeEstimate, finishedSize, materials, notes, defaultPattern, createdAt) VALUES ('template_130', 'Heirloom Pumpkin', 'A softly ribbed pumpkin with a little stalk — a centrepiece for the autumn table. Cinch the body for its ridges.', 'Intermediate', 'Home Decor', '["seasonal","pumpkin","decor"]', NULL, '5.0 mm', 'Worsted', '3–4 hrs', 'Approximately 14 cm (6 in) at the largest dimension', '["Worsted yarn in marigold, chocolate","5.0 mm hook","Tapestry needle","Scissors"]', '[]', '["Body — in marigold yarn: work the following in continuous rounds.","Body — Round 1: Magic ring. 6 single crochet into ring. Pull ring closed. (6 stitches)","Body — Round 2: 2 single crochet in each stitch around. (12 stitches)","Body — Round 3: [Single crochet in next stitch, 2 single crochet in next stitch] repeat 6 times. (18 stitches)","Body — Round 4: [Single crochet in next 2 stitches, 2 single crochet in next stitch] repeat 6 times. (24 stitches)","Body — Round 5: [Single crochet in next 3 stitches, 2 single crochet in next stitch] repeat 6 times. (30 stitches)","Body — Round 6: [Single crochet in next 4 stitches, 2 single crochet in next stitch] repeat 6 times. (36 stitches)","Body — Round 7: [Single crochet in next 5 stitches, 2 single crochet in next stitch] repeat 6 times. (42 stitches)","Body — Round 8: [Single crochet in next 6 stitches, 2 single crochet in next stitch] repeat 6 times. (48 stitches)","Body — Round 9: [Single crochet in next 7 stitches, 2 single crochet in next stitch] repeat 6 times. (54 stitches)","Body — Round 10: [Single crochet in next 8 stitches, 2 single crochet in next stitch] repeat 6 times. (60 stitches)","Body — Round 11: [Single crochet in next 9 stitches, 2 single crochet in next stitch] repeat 6 times. (66 stitches)","Body — Round 12: [Single crochet in next 10 stitches, 2 single crochet in next stitch] repeat 6 times. (72 stitches)","Body — Round 13: [Single crochet in next 11 stitches, 2 single crochet in next stitch] repeat 6 times. (78 stitches)","Body — Round 14: Single crochet in each stitch around. (78 stitches)","Body — Round 15: [Single crochet in next 11 stitches, single crochet 2 together] repeat 6 times. (72 stitches)","Body — Round 16: [Single crochet in next 10 stitches, single crochet 2 together] repeat 6 times. (66 stitches)","Body — Round 17: [Single crochet in next 9 stitches, single crochet 2 together] repeat 6 times. (60 stitches)","Body — Round 18: [Single crochet in next 8 stitches, single crochet 2 together] repeat 6 times. (54 stitches)","Body — Round 19: [Single crochet in next 7 stitches, single crochet 2 together] repeat 6 times. (48 stitches)","Body — Round 20: [Single crochet in next 6 stitches, single crochet 2 together] repeat 6 times. (42 stitches)","Body — Round 21: [Single crochet in next 5 stitches, single crochet 2 together] repeat 6 times. (36 stitches)","Body — Round 22: [Single crochet in next 4 stitches, single crochet 2 together] repeat 6 times. (30 stitches)","Body — Round 23: [Single crochet in next 3 stitches, single crochet 2 together] repeat 6 times. (24 stitches)","Body — Round 24: [Single crochet in next 2 stitches, single crochet 2 together] repeat 6 times. (18 stitches)","Body — Stuffing: Stuff firmly with polyfill, shaping as you go. Keep adding stuffing as the opening closes.","Body — Round 25: [Single crochet in next stitch, single crochet 2 together] repeat 6 times. (12 stitches)","Body — Round 26: [Single crochet 2 together] repeat 6 times. (6 stitches)","Body — Finishing: Fasten off leaving a long tail. Thread the tail through the front loops of the remaining 6 stitches, pull tight to close, and weave in the end.","Stalk — in chocolate yarn: work the following in continuous rounds.","Stalk — Round 1: Magic ring. 6 single crochet into ring. Pull ring closed. (6 stitches)","Stalk — Round 2: 2 single crochet in each stitch around. (12 stitches)","Stalk — Round 3: [Single crochet in next stitch, 2 single crochet in next stitch] repeat 6 times. (18 stitches)","Stalk — Rounds 4–14: Working in back loops only for this round, then through both loops: single crochet in each stitch around. (18 stitches each round)","Stalk — Finishing: Fasten off and weave in ends.","Assembly: Stuff the body and sew the stalk to the centre top.","Embellishment: Wrap yarn vertically around the body and pull snug to form ribs."]', '2026-06-30T00:00:00.000Z')
  ON CONFLICT(id) DO UPDATE SET name = excluded.name, description = excluded.description, difficulty = excluded.difficulty, category = excluded.category, tags = excluded.tags, imageUrl = excluded.imageUrl, hookSize = excluded.hookSize, yarnWeight = excluded.yarnWeight, timeEstimate = excluded.timeEstimate, finishedSize = excluded.finishedSize, materials = excluded.materials, notes = excluded.notes, defaultPattern = excluded.defaultPattern;
